#!/usr/bin/env python3
"""PhotoWing deploy script — auto-sudo, auto-detect, zero-config"""
import gzip,base64,os,subprocess,sys,tempfile,urllib.request

# ==== EMBEDDED HTML (gzip+base64) ====

HTML_B64 = ""


# ==== Helpers ====
def write_file(path, content):
    try:
        os.makedirs(os.path.dirname(path), exist_ok=True)
        with open(path, "w") as f:
            f.write(content)
        return True
    except PermissionError:
        with tempfile.NamedTemporaryFile(mode="w", suffix=".tmp", delete=False) as tf:
            tf.write(content)
            tmp = tf.name
        r = subprocess.run(["sudo", "cp", tmp, path], stdout=subprocess.PIPE, stderr=subprocess.PIPE, universal_newlines=True)
        os.unlink(tmp)
        if r.returncode != 0:
            print(f"FAILED to write {path}: {r.stderr.strip()}")
            return False
        return True

def try_cmd(cmd_parts):
    for prefix in ([], ["sudo"]):
        try:
            r = subprocess.run(prefix + list(cmd_parts), stdout=subprocess.PIPE, stderr=subprocess.PIPE, universal_newlines=True)
            return r.returncode == 0, (r.stdout + r.stderr).strip()
        except FileNotFoundError:
            continue
    return False, "command not found"

def already_working():
    try:
        resp = urllib.request.urlopen("http://127.0.0.1/photowing/", timeout=5)
        return resp.status == 200
    except:
        return False

# ==== Step 1: Write HTML ====
html = gzip.decompress(base64.b64decode(HTML_B64)).decode()
if write_file("/opt/photowing/index.html", html):
    print(f"HTML written: {len(html)} bytes")

# ==== Step 2: Nginx config ====
if already_working():
    print("Photowing already accessible, skipping nginx config")
else:
    # Try to find existing server_name
    server_name = "47.82.103.246.sslip.io"
    ok, out = try_cmd(["grep", "-rl", "sslip.io", "/etc/nginx/"])
    if ok and out:
        # Parse existing config to find server block structure
        pass  # Use default server_name
    
    NGINX_CONF = """server {
    listen 80;
    server_name SERVER_NAME_PLACEHOLDER;

    location /photowing/ {
        alias /opt/photowing/;
        index index.html;
        try_files $uri $uri/ /photowing/index.html;
        add_header X-Frame-Options "SAMEORIGIN" always;
        add_header X-Content-Type-Options "nosniff" always;
        add_header Permissions-Policy "camera=(self),microphone=(self)" always;
        expires -1;
    }
}
""".replace("SERVER_NAME_PLACEHOLDER", server_name)

    if write_file("/etc/nginx/conf.d/photowing.conf", NGINX_CONF):
        print("Nginx config written")

# ==== Step 3: Reload nginx ====
ok, out = try_cmd(["nginx", "-t"])
if ok:
    ok2, out2 = try_cmd(["systemctl", "reload", "nginx"])
    if not ok2:
        ok2, out2 = try_cmd(["service", "nginx", "reload"])
    print("Nginx reloaded OK" if ok2 else f"Nginx reload FAILED:\n{out2[:300]}")
else:
    print(f"Nginx test FAILED:\n{out[:500]}")
    print("\nYou may need to manually fix the nginx config.")
    print("The HTML file is already deployed at /opt/photowing/index.html")

# ==== Step 4: Verify ====
try:
    resp = urllib.request.urlopen("http://127.0.0.1/photowing/", timeout=10)
    print(f"UP: HTTP {resp.status} - {len(resp.read())} bytes")
except Exception as e:
    print(f"DOWN: {e}")